    /* Methods. */

    /**
     * Get ITM_TPR's PRIVMASK field.
     *
     * Bit mask to enable tracing on ITM stimulus ports
     */
    inline uint8_t get_ITM_TPR() volatile
    {
        return ITM_TPR & 0xfu;
    }

    /**
     * Set ITM_TPR's PRIVMASK field.
     *
     * Bit mask to enable tracing on ITM stimulus ports
     */
    inline void set_ITM_TPR(uint8_t value) volatile
    {
        uint32_t curr = ITM_TPR;

        curr &= ~(0xfu);
        curr |= (value & 0xfu);

        ITM_TPR = curr;
    }

    /**
     * Get ITM_TCR's ITMENA bit.
     *
     * Enables the ITM
     */
    inline bool get_ITM_TCR_ITMENA() volatile
    {
        return ITM_TCR & 1u;
    }

    /**
     * Set ITM_TCR's ITMENA bit.
     *
     * Enables the ITM
     */
    inline void set_ITM_TCR_ITMENA() volatile
    {
        ITM_TCR |= 1u;
    }

    /**
     * Clear ITM_TCR's ITMENA bit.
     *
     * Enables the ITM
     */
    inline void clear_ITM_TCR_ITMENA() volatile
    {
        ITM_TCR &= ~(1u);
    }

    /**
     * Toggle ITM_TCR's ITMENA bit.
     *
     * Enables the ITM
     */
    inline void toggle_ITM_TCR_ITMENA() volatile
    {
        ITM_TCR ^= 1u;
    }

    /**
     * Get ITM_TCR's TSENA bit.
     *
     * Enables Local timestamp generation
     */
    inline bool get_ITM_TCR_TSENA() volatile
    {
        return ITM_TCR & (1u << 1u);
    }

    /**
     * Set ITM_TCR's TSENA bit.
     *
     * Enables Local timestamp generation
     */
    inline void set_ITM_TCR_TSENA() volatile
    {
        ITM_TCR |= 1u << 1u;
    }

    /**
     * Clear ITM_TCR's TSENA bit.
     *
     * Enables Local timestamp generation
     */
    inline void clear_ITM_TCR_TSENA() volatile
    {
        ITM_TCR &= ~(1u << 1u);
    }

    /**
     * Toggle ITM_TCR's TSENA bit.
     *
     * Enables Local timestamp generation
     */
    inline void toggle_ITM_TCR_TSENA() volatile
    {
        ITM_TCR ^= 1u << 1u;
    }

    /**
     * Get ITM_TCR's SYNCENA bit.
     *
     * Enables Synchronization packet transmission for a synchronous TPIU
     */
    inline bool get_ITM_TCR_SYNCENA() volatile
    {
        return ITM_TCR & (1u << 2u);
    }

    /**
     * Set ITM_TCR's SYNCENA bit.
     *
     * Enables Synchronization packet transmission for a synchronous TPIU
     */
    inline void set_ITM_TCR_SYNCENA() volatile
    {
        ITM_TCR |= 1u << 2u;
    }

    /**
     * Clear ITM_TCR's SYNCENA bit.
     *
     * Enables Synchronization packet transmission for a synchronous TPIU
     */
    inline void clear_ITM_TCR_SYNCENA() volatile
    {
        ITM_TCR &= ~(1u << 2u);
    }

    /**
     * Toggle ITM_TCR's SYNCENA bit.
     *
     * Enables Synchronization packet transmission for a synchronous TPIU
     */
    inline void toggle_ITM_TCR_SYNCENA() volatile
    {
        ITM_TCR ^= 1u << 2u;
    }

    /**
     * Get ITM_TCR's TXENA bit.
     *
     * Enables forwarding of hardware event packet from the DWT unit to the ITM
     * for output to the TPIU
     */
    inline bool get_ITM_TCR_TXENA() volatile
    {
        return ITM_TCR & (1u << 3u);
    }

    /**
     * Set ITM_TCR's TXENA bit.
     *
     * Enables forwarding of hardware event packet from the DWT unit to the ITM
     * for output to the TPIU
     */
    inline void set_ITM_TCR_TXENA() volatile
    {
        ITM_TCR |= 1u << 3u;
    }

    /**
     * Clear ITM_TCR's TXENA bit.
     *
     * Enables forwarding of hardware event packet from the DWT unit to the ITM
     * for output to the TPIU
     */
    inline void clear_ITM_TCR_TXENA() volatile
    {
        ITM_TCR &= ~(1u << 3u);
    }

    /**
     * Toggle ITM_TCR's TXENA bit.
     *
     * Enables forwarding of hardware event packet from the DWT unit to the ITM
     * for output to the TPIU
     */
    inline void toggle_ITM_TCR_TXENA() volatile
    {
        ITM_TCR ^= 1u << 3u;
    }

    /**
     * Get ITM_TCR's SWOENA bit.
     *
     * Enables asynchronous clocking of the timestamp counter
     */
    inline bool get_ITM_TCR_SWOENA() volatile
    {
        return ITM_TCR & (1u << 4u);
    }

    /**
     * Set ITM_TCR's SWOENA bit.
     *
     * Enables asynchronous clocking of the timestamp counter
     */
