    {
        ITM_TCR &= ~(1u << 4u);
    }

    /**
     * Toggle ITM_TCR's SWOENA bit.
     *
     * Enables asynchronous clocking of the timestamp counter
     */
    inline void toggle_ITM_TCR_SWOENA() volatile
    {
        ITM_TCR ^= 1u << 4u;
    }

    /**
     * Get ITM_TCR's STALLENA bit.
     *
     * Stall the PE to guarantee delivery of Data Trace packets.
     */
