    /**
     * Get all of ITM_TCR's bit fields.
     *
     * (read-write) Configures and controls transfers through the ITM interface
     */
    inline void get_ITM_TCR(bool &ITMENA, bool &TSENA, bool &SYNCENA,
                            bool &TXENA, bool &SWOENA, bool &STALLENA,
                            uint8_t &TSPRESCALE, uint8_t &GTSFREQ,
                            uint8_t &TRACEBUSID, bool &BUSY) volatile
    {
        uint32_t curr = ITM_TCR;

        ITMENA = curr & 1u;
        TSENA = curr & (1u << 1u);
        SYNCENA = curr & (1u << 2u);
        TXENA = curr & (1u << 3u);
        SWOENA = curr & (1u << 4u);
        STALLENA = curr & (1u << 5u);
        TSPRESCALE = (curr >> 8u) & 0b11u;
        GTSFREQ = (curr >> 10u) & 0b11u;
        TRACEBUSID = (curr >> 16u) & 0b1111111u;
        BUSY = curr & (1u << 23u);
    }

    /**
     * Set all of ITM_TCR's bit fields.
     *
     * (read-write) Configures and controls transfers through the ITM interface
     */
    inline void set_ITM_TCR(bool ITMENA, bool TSENA, bool SYNCENA, bool TXENA,
                            bool SWOENA, bool STALLENA, uint8_t TSPRESCALE,
                            uint8_t GTSFREQ, uint8_t TRACEBUSID) volatile
    {
        uint32_t curr = ITM_TCR;

        curr &= ~(0b1u);
        curr |= (ITMENA & 0b1u);
        curr &= ~(0b1u << 1u);
        curr |= (TSENA & 0b1u) << 1u;
        curr &= ~(0b1u << 2u);
        curr |= (SYNCENA & 0b1u) << 2u;
        curr &= ~(0b1u << 3u);
        curr |= (TXENA & 0b1u) << 3u;
        curr &= ~(0b1u << 4u);
        curr |= (SWOENA & 0b1u) << 4u;
        curr &= ~(0b1u << 5u);
        curr |= (STALLENA & 0b1u) << 5u;
        curr &= ~(0b11u << 8u);
        curr |= (TSPRESCALE & 0b11u) << 8u;
        curr &= ~(0b11u << 10u);
        curr |= (GTSFREQ & 0b11u) << 10u;
        curr &= ~(0b1111111u << 16u);
        curr |= (TRACEBUSID & 0b1111111u) << 16u;

        ITM_TCR = curr;
    }

