        curr &= ~(0xfu << 5u);
        curr |= (POSTINIT & 0xfu) << 5u;
        curr &= ~(0b1u << 9u);
        curr |= (CYCTAP & 0b1u) << 9u;
        curr &= ~(0b11u << 10u);
        curr |= (SYNCTAP & 0b11u) << 10u;
        curr &= ~(0b1u << 12u);
        curr |= (PCSAMPLENA & 0b1u) << 12u;
        curr &= ~(0b1u << 16u);
        curr |= (EXTTRCENA & 0b1u) << 16u;
        curr &= ~(0b1u << 17u);
        curr |= (CPIEVTENA & 0b1u) << 17u;
        curr &= ~(0b1u << 18u);
        curr |= (EXCEVTENA & 0b1u) << 18u;
        curr &= ~(0b1u << 19u);
        curr |= (SLEEPEVTENA & 0b1u) << 19u;
        curr &= ~(0b1u << 20u);
        curr |= (LSUEVTENA & 0b1u) << 20u;
        curr &= ~(0b1u << 21u);
        curr |= (FOLDEVTENA & 0b1u) << 21u;
        curr &= ~(0b1u << 22u);
        curr |= (CYCEVTENA & 0b1u) << 22u;
        curr &= ~(0b1u << 23u);
        curr |= (CYCDISS & 0b1u) << 23u;

