    /**
     * Get all of FP_CTRL's bit fields.
     *
     * (read-write) Provides FPB implementation information, and the global
     * enable for the FPB unit
     */
    inline void get_FP_CTRL(bool &ENABLE, bool &KEY, uint8_t &NUM_CODE_7_4_,
                            uint8_t &NUM_LIT, uint8_t &NUM_CODE_14_12_,
                            uint8_t &REV) volatile
    {
        uint32_t curr = FP_CTRL;

        ENABLE = curr & 1u;
        KEY = curr & (1u << 1u);
        NUM_CODE_7_4_ = (curr >> 4u) & 0xfu;
        NUM_LIT = (curr >> 8u) & 0xfu;
        NUM_CODE_14_12_ = (curr >> 12u) & 0b111u;
        REV = (curr >> 28u) & 0xfu;
    }

    /**
     * Set all of FP_CTRL's bit fields.
     *
     * (read-write) Provides FPB implementation information, and the global
     * enable for the FPB unit
     */
    inline void set_FP_CTRL(bool ENABLE, bool KEY) volatile
    {
        uint32_t curr = FP_CTRL;

        curr &= ~(0b1u);
        curr |= (ENABLE & 0b1u);
        curr &= ~(0b1u << 1u);
        curr |= (KEY & 0b1u) << 1u;

        FP_CTRL = curr;
    }

