    /**
     * Get all of ACTLR's bit fields.
     *
     * (read-write) Provides IMPLEMENTATION DEFINED configuration and control
     * options
     */
    inline void get_ACTLR(bool &DISMCYCINT, bool &DISFOLD, bool &DISOOFP,
                          bool &FPEXCODIS, bool &DISITMATBFLUSH,
                          bool &EXTEXCLALL) volatile
    {
        uint32_t curr = ACTLR;

        DISMCYCINT = curr & 1u;
        DISFOLD = curr & (1u << 2u);
        DISOOFP = curr & (1u << 9u);
        FPEXCODIS = curr & (1u << 10u);
        DISITMATBFLUSH = curr & (1u << 12u);
        EXTEXCLALL = curr & (1u << 29u);
    }

    /**
     * Set all of ACTLR's bit fields.
     *
     * (read-write) Provides IMPLEMENTATION DEFINED configuration and control
     * options
     */
    inline void set_ACTLR(bool DISMCYCINT, bool DISFOLD, bool DISOOFP,
                          bool FPEXCODIS, bool DISITMATBFLUSH,
                          bool EXTEXCLALL) volatile
    {
        uint32_t curr = ACTLR;

        curr &= ~(0b1u);
        curr |= (DISMCYCINT & 0b1u);
        curr &= ~(0b1u << 2u);
        curr |= (DISFOLD & 0b1u) << 2u;
        curr &= ~(0b1u << 9u);
        curr |= (DISOOFP & 0b1u) << 9u;
        curr &= ~(0b1u << 10u);
        curr |= (FPEXCODIS & 0b1u) << 10u;
        curr &= ~(0b1u << 12u);
        curr |= (DISITMATBFLUSH & 0b1u) << 12u;
        curr &= ~(0b1u << 29u);
        curr |= (EXTEXCLALL & 0b1u) << 29u;

        ACTLR = curr;
    }

