    {
        return (CPUID >> 16u) & 0xfu;
    }

    /**
     * Get CPUID's VARIANT field.
     *
     * IMPLEMENTATION DEFINED variant number. Typically, this field is used to
     * distinguish between different product variants, or major revisions of a
     * product
     */
    inline uint8_t get_CPUID_VARIANT() volatile
    {
        return (CPUID >> 20u) & 0xfu;
    }

    /**
     * Get CPUID's IMPLEMENTER field.
     *
     * This field must hold an implementer code that has been assigned by ARM
     */
    inline uint8_t get_CPUID_IMPLEMENTER() volatile
    {
        return (CPUID >> 24u) & 0xffu;
    }

    /**
     * Get all of CPUID's bit fields.
     *
     * (read-only) Provides identification information for the PE, including an
     * implementer code for the device and a device ID number
     */
    inline void get_CPUID(uint8_t &REVISION, uint16_t &PARTNO,
                          uint8_t &ARCHITECTURE, uint8_t &VARIANT,
                          uint8_t &IMPLEMENTER) volatile
    {
        uint32_t curr = CPUID;

        REVISION = curr & 0xfu;
        PARTNO = (curr >> 4u) & 0xfffu;
        ARCHITECTURE = (curr >> 16u) & 0xfu;
        VARIANT = (curr >> 20u) & 0xfu;
        IMPLEMENTER = (curr >> 24u) & 0xffu;
    }

