    /**
     * Get all of SHCSR's bit fields.
     *
     * (read-write) Provides access to the active and pending status of system
     * exceptions
     */
    inline void get_SHCSR(bool &MEMFAULTACT, bool &BUSFAULTACT,
                          bool &HARDFAULTACT, bool &USGFAULTACT,
                          bool &SECUREFAULTACT, bool &NMIACT, bool &SVCALLACT,
                          bool &MONITORACT, bool &PENDSVACT, bool &SYSTICKACT,
                          bool &USGFAULTPENDED, bool &MEMFAULTPENDED,
                          bool &BUSFAULTPENDED, bool &SVCALLPENDED,
                          bool &MEMFAULTENA, bool &BUSFAULTENA,
                          bool &USGFAULTENA, bool &SECUREFAULTENA,
                          bool &SECUREFAULTPENDED,
                          bool &HARDFAULTPENDED) volatile
    {
        uint32_t curr = SHCSR;

        MEMFAULTACT = curr & 1u;
        BUSFAULTACT = curr & (1u << 1u);
        HARDFAULTACT = curr & (1u << 2u);
        USGFAULTACT = curr & (1u << 3u);
        SECUREFAULTACT = curr & (1u << 4u);
        NMIACT = curr & (1u << 5u);
        SVCALLACT = curr & (1u << 7u);
        MONITORACT = curr & (1u << 8u);
        PENDSVACT = curr & (1u << 10u);
        SYSTICKACT = curr & (1u << 11u);
        USGFAULTPENDED = curr & (1u << 12u);
        MEMFAULTPENDED = curr & (1u << 13u);
        BUSFAULTPENDED = curr & (1u << 14u);
        SVCALLPENDED = curr & (1u << 15u);
        MEMFAULTENA = curr & (1u << 16u);
        BUSFAULTENA = curr & (1u << 17u);
        USGFAULTENA = curr & (1u << 18u);
        SECUREFAULTENA = curr & (1u << 19u);
        SECUREFAULTPENDED = curr & (1u << 20u);
        HARDFAULTPENDED = curr & (1u << 21u);
    }

    /**
     * Set all of SHCSR's bit fields.
     *
     * (read-write) Provides access to the active and pending status of system
     * exceptions
     */
    inline void set_SHCSR(bool MEMFAULTACT, bool BUSFAULTACT,
                          bool HARDFAULTACT, bool USGFAULTACT,
                          bool SECUREFAULTACT, bool NMIACT, bool SVCALLACT,
                          bool MONITORACT, bool PENDSVACT, bool SYSTICKACT,
                          bool USGFAULTPENDED, bool MEMFAULTPENDED,
                          bool BUSFAULTPENDED, bool SVCALLPENDED,
                          bool MEMFAULTENA, bool BUSFAULTENA, bool USGFAULTENA,
                          bool SECUREFAULTENA, bool SECUREFAULTPENDED,
                          bool HARDFAULTPENDED) volatile
    {
        uint32_t curr = SHCSR;

        curr &= ~(0b1u);
        curr |= (MEMFAULTACT & 0b1u);
        curr &= ~(0b1u << 1u);
        curr |= (BUSFAULTACT & 0b1u) << 1u;
        curr &= ~(0b1u << 2u);
        curr |= (HARDFAULTACT & 0b1u) << 2u;
        curr &= ~(0b1u << 3u);
        curr |= (USGFAULTACT & 0b1u) << 3u;
        curr &= ~(0b1u << 4u);
        curr |= (SECUREFAULTACT & 0b1u) << 4u;
        curr &= ~(0b1u << 5u);
        curr |= (NMIACT & 0b1u) << 5u;
        curr &= ~(0b1u << 7u);
        curr |= (SVCALLACT & 0b1u) << 7u;
        curr &= ~(0b1u << 8u);
        curr |= (MONITORACT & 0b1u) << 8u;
        curr &= ~(0b1u << 10u);
        curr |= (PENDSVACT & 0b1u) << 10u;
        curr &= ~(0b1u << 11u);
        curr |= (SYSTICKACT & 0b1u) << 11u;
        curr &= ~(0b1u << 12u);
        curr |= (USGFAULTPENDED & 0b1u) << 12u;
        curr &= ~(0b1u << 13u);
        curr |= (MEMFAULTPENDED & 0b1u) << 13u;
        curr &= ~(0b1u << 14u);
        curr |= (BUSFAULTPENDED & 0b1u) << 14u;
        curr &= ~(0b1u << 15u);
        curr |= (SVCALLPENDED & 0b1u) << 15u;
        curr &= ~(0b1u << 16u);
        curr |= (MEMFAULTENA & 0b1u) << 16u;
        curr &= ~(0b1u << 17u);
        curr |= (BUSFAULTENA & 0b1u) << 17u;
        curr &= ~(0b1u << 18u);
        curr |= (USGFAULTENA & 0b1u) << 18u;
        curr &= ~(0b1u << 19u);
        curr |= (SECUREFAULTENA & 0b1u) << 19u;
        curr &= ~(0b1u << 20u);
        curr |= (SECUREFAULTPENDED & 0b1u) << 20u;
        curr &= ~(0b1u << 21u);
        curr |= (HARDFAULTPENDED & 0b1u) << 21u;

        SHCSR = curr;
    }

