    /**
     * Get all of CFSR's bit fields.
     *
     * (read-write) Contains the three Configurable Fault Status Registers.
     *
     *                     31:16 UFSR: Provides information on UsageFault
     * exceptions
     *
     *                     15:8 BFSR: Provides information on BusFault
     * exceptions
     *
     *                     7:0 MMFSR: Provides information on MemManage
     * exceptions
     */
    inline void get_CFSR(uint8_t &MMFSR, bool &BFSR_IBUSERR,
                         bool &BFSR_PRECISERR, bool &BFSR_IMPRECISERR,
                         bool &BFSR_UNSTKERR, bool &BFSR_STKERR,
                         bool &BFSR_LSPERR, bool &BFSR_BFARVALID,
                         bool &UFSR_UNDEFINSTR, bool &UFSR_INVSTATE,
                         bool &UFSR_INVPC, bool &UFSR_NOCP, bool &UFSR_STKOF,
                         bool &UFSR_UNALIGNED, bool &UFSR_DIVBYZERO) volatile
    {
        uint32_t curr = CFSR;

        MMFSR = curr & 0xffu;
        BFSR_IBUSERR = curr & (1u << 8u);
        BFSR_PRECISERR = curr & (1u << 9u);
        BFSR_IMPRECISERR = curr & (1u << 10u);
        BFSR_UNSTKERR = curr & (1u << 11u);
        BFSR_STKERR = curr & (1u << 12u);
        BFSR_LSPERR = curr & (1u << 13u);
        BFSR_BFARVALID = curr & (1u << 15u);
        UFSR_UNDEFINSTR = curr & (1u << 16u);
        UFSR_INVSTATE = curr & (1u << 17u);
        UFSR_INVPC = curr & (1u << 18u);
        UFSR_NOCP = curr & (1u << 19u);
        UFSR_STKOF = curr & (1u << 20u);
        UFSR_UNALIGNED = curr & (1u << 24u);
        UFSR_DIVBYZERO = curr & (1u << 25u);
    }

    /**
     * Set all of CFSR's bit fields.
     *
     * (read-write) Contains the three Configurable Fault Status Registers.
     *
     *                     31:16 UFSR: Provides information on UsageFault
     * exceptions
     *
     *                     15:8 BFSR: Provides information on BusFault
     * exceptions
     *
     *                     7:0 MMFSR: Provides information on MemManage
     * exceptions
     */
    inline void set_CFSR(uint8_t MMFSR, bool BFSR_IBUSERR, bool BFSR_PRECISERR,
                         bool BFSR_IMPRECISERR, bool BFSR_UNSTKERR,
                         bool BFSR_STKERR, bool BFSR_LSPERR,
                         bool BFSR_BFARVALID, bool UFSR_UNDEFINSTR,
                         bool UFSR_INVSTATE, bool UFSR_INVPC, bool UFSR_NOCP,
                         bool UFSR_STKOF, bool UFSR_UNALIGNED,
                         bool UFSR_DIVBYZERO) volatile
    {
        uint32_t curr = CFSR;

        curr &= ~(0xffu);
        curr |= (MMFSR & 0xffu);
        curr &= ~(0b1u << 8u);
        curr |= (BFSR_IBUSERR & 0b1u) << 8u;
        curr &= ~(0b1u << 9u);
        curr |= (BFSR_PRECISERR & 0b1u) << 9u;
        curr &= ~(0b1u << 10u);
        curr |= (BFSR_IMPRECISERR & 0b1u) << 10u;
        curr &= ~(0b1u << 11u);
        curr |= (BFSR_UNSTKERR & 0b1u) << 11u;
        curr &= ~(0b1u << 12u);
        curr |= (BFSR_STKERR & 0b1u) << 12u;
        curr &= ~(0b1u << 13u);
        curr |= (BFSR_LSPERR & 0b1u) << 13u;
        curr &= ~(0b1u << 15u);
        curr |= (BFSR_BFARVALID & 0b1u) << 15u;
        curr &= ~(0b1u << 16u);
        curr |= (UFSR_UNDEFINSTR & 0b1u) << 16u;
        curr &= ~(0b1u << 17u);
        curr |= (UFSR_INVSTATE & 0b1u) << 17u;
        curr &= ~(0b1u << 18u);
        curr |= (UFSR_INVPC & 0b1u) << 18u;
        curr &= ~(0b1u << 19u);
        curr |= (UFSR_NOCP & 0b1u) << 19u;
        curr &= ~(0b1u << 20u);
        curr |= (UFSR_STKOF & 0b1u) << 20u;
        curr &= ~(0b1u << 24u);
        curr |= (UFSR_UNALIGNED & 0b1u) << 24u;
        curr &= ~(0b1u << 25u);
        curr |= (UFSR_DIVBYZERO & 0b1u) << 25u;

        CFSR = curr;
    }

