    /**
     * Get all of HFSR's bit fields.
     *
     * (read-write) Shows the cause of any HardFaults
     */
    inline void get_HFSR(bool &VECTTBL, bool &FORCED, bool &DEBUGEVT) volatile
    {
        uint32_t curr = HFSR;

        VECTTBL = curr & (1u << 1u);
        FORCED = curr & (1u << 30u);
        DEBUGEVT = curr & (1u << 31u);
    }

    /**
     * Set all of HFSR's bit fields.
     *
     * (read-write) Shows the cause of any HardFaults
     */
    inline void set_HFSR(bool VECTTBL, bool FORCED, bool DEBUGEVT) volatile
    {
        uint32_t curr = HFSR;

        curr &= ~(0b1u << 1u);
        curr |= (VECTTBL & 0b1u) << 1u;
        curr &= ~(0b1u << 30u);
        curr |= (FORCED & 0b1u) << 30u;
        curr &= ~(0b1u << 31u);
        curr |= (DEBUGEVT & 0b1u) << 31u;

        HFSR = curr;
    }

