        CP1 = (curr >> 2u) & 0b11u;
        CP2 = (curr >> 4u) & 0b11u;
        CP3 = (curr >> 6u) & 0b11u;
        CP4 = (curr >> 8u) & 0b11u;
        CP5 = (curr >> 10u) & 0b11u;
        CP6 = (curr >> 12u) & 0b11u;
        CP7 = (curr >> 14u) & 0b11u;
        CP10 = (curr >> 20u) & 0b11u;
        CP11 = (curr >> 22u) & 0b11u;
