        curr &= ~(0b11u);
        curr |= (CP0 & 0b11u);
        curr &= ~(0b11u << 2u);
        curr |= (CP1 & 0b11u) << 2u;
        curr &= ~(0b11u << 4u);
        curr |= (CP2 & 0b11u) << 4u;
        curr &= ~(0b11u << 6u);
        curr |= (CP3 & 0b11u) << 6u;
        curr &= ~(0b11u << 8u);
        curr |= (CP4 & 0b11u) << 8u;
        curr &= ~(0b11u << 10u);
        curr |= (CP5 & 0b11u) << 10u;
