    /**
     * Get all of SFSR's bit fields.
     *
     * (read-write) Provides information about any security related faults
     */
    inline void get_SFSR(bool &INVEP, bool &INVIS, bool &INVER, bool &AUVIOL,
                         bool &INVTRAN, bool &LSPERR, bool &SFARVALID,
                         bool &LSERR) volatile
    {
        uint32_t curr = SFSR;

        INVEP = curr & 1u;
        INVIS = curr & (1u << 1u);
        INVER = curr & (1u << 2u);
        AUVIOL = curr & (1u << 3u);
        INVTRAN = curr & (1u << 4u);
        LSPERR = curr & (1u << 5u);
        SFARVALID = curr & (1u << 6u);
        LSERR = curr & (1u << 7u);
    }

    /**
     * Set all of SFSR's bit fields.
     *
     * (read-write) Provides information about any security related faults
     */
    inline void set_SFSR(bool INVEP, bool INVIS, bool INVER, bool AUVIOL,
                         bool INVTRAN, bool LSPERR, bool SFARVALID,
                         bool LSERR) volatile
    {
        uint32_t curr = SFSR;

        curr &= ~(0b1u);
        curr |= (INVEP & 0b1u);
        curr &= ~(0b1u << 1u);
        curr |= (INVIS & 0b1u) << 1u;
        curr &= ~(0b1u << 2u);
        curr |= (INVER & 0b1u) << 2u;
        curr &= ~(0b1u << 3u);
        curr |= (AUVIOL & 0b1u) << 3u;
        curr &= ~(0b1u << 4u);
        curr |= (INVTRAN & 0b1u) << 4u;
        curr &= ~(0b1u << 5u);
        curr |= (LSPERR & 0b1u) << 5u;
        curr &= ~(0b1u << 6u);
        curr |= (SFARVALID & 0b1u) << 6u;
        curr &= ~(0b1u << 7u);
        curr |= (LSERR & 0b1u) << 7u;

        SFSR = curr;
    }

