    /**
     * Get all of DHCSR's bit fields.
     *
     * (read-write) Controls halting debug
     */
    inline void get_DHCSR(bool &C_DEBUGEN, bool &C_HALT, bool &C_STEP,
                          bool &C_MASKINTS, bool &C_SNAPSTALL, bool &S_REGRDY,
                          bool &S_HALT, bool &S_SLEEP, bool &S_LOCKUP,
                          bool &S_SDE, bool &S_RETIRE_ST, bool &S_RESET_ST,
                          bool &S_RESTART_ST) volatile
    {
        uint32_t curr = DHCSR;

        C_DEBUGEN = curr & 1u;
        C_HALT = curr & (1u << 1u);
        C_STEP = curr & (1u << 2u);
        C_MASKINTS = curr & (1u << 3u);
        C_SNAPSTALL = curr & (1u << 5u);
        S_REGRDY = curr & (1u << 16u);
        S_HALT = curr & (1u << 17u);
        S_SLEEP = curr & (1u << 18u);
        S_LOCKUP = curr & (1u << 19u);
        S_SDE = curr & (1u << 20u);
        S_RETIRE_ST = curr & (1u << 24u);
        S_RESET_ST = curr & (1u << 25u);
        S_RESTART_ST = curr & (1u << 26u);
    }

