    {
        uint32_t curr = DCRSR;

        curr &= ~(0b1111111u);
        curr |= (REGSEL & 0b1111111u);
        curr &= ~(0b1u << 16u);
        curr |= (REGWNR & 0b1u) << 16u;

        DCRSR = curr;
    }

