    /**
     * Get all of DEMCR's bit fields.
     *
     * (read-write) Manages vector catch behavior and DebugMonitor handling
     * when debugging
     */
    inline void get_DEMCR(bool &VC_CORERESET, bool &VC_MMERR, bool &VC_NOCPERR,
                          bool &VC_CHKERR, bool &VC_STATERR, bool &VC_BUSERR,
                          bool &VC_INTERR, bool &VC_HARDERR, bool &VC_SFERR,
                          bool &MON_EN, bool &MON_PEND, bool &MON_STEP,
                          bool &MON_REQ, bool &SDME, bool &TRCENA) volatile
    {
        uint32_t curr = DEMCR;

        VC_CORERESET = curr & 1u;
        VC_MMERR = curr & (1u << 4u);
        VC_NOCPERR = curr & (1u << 5u);
        VC_CHKERR = curr & (1u << 6u);
        VC_STATERR = curr & (1u << 7u);
        VC_BUSERR = curr & (1u << 8u);
        VC_INTERR = curr & (1u << 9u);
        VC_HARDERR = curr & (1u << 10u);
        VC_SFERR = curr & (1u << 11u);
        MON_EN = curr & (1u << 16u);
        MON_PEND = curr & (1u << 17u);
        MON_STEP = curr & (1u << 18u);
        MON_REQ = curr & (1u << 19u);
        SDME = curr & (1u << 20u);
        TRCENA = curr & (1u << 24u);
    }

    /**
     * Set all of DEMCR's bit fields.
     *
     * (read-write) Manages vector catch behavior and DebugMonitor handling
     * when debugging
     */
    inline void set_DEMCR(bool VC_CORERESET, bool VC_MMERR, bool VC_NOCPERR,
                          bool VC_CHKERR, bool VC_STATERR, bool VC_BUSERR,
                          bool VC_INTERR, bool VC_HARDERR, bool VC_SFERR,
                          bool MON_EN, bool MON_PEND, bool MON_STEP,
                          bool MON_REQ, bool TRCENA) volatile
    {
        uint32_t curr = DEMCR;

        curr &= ~(0b1u);
        curr |= (VC_CORERESET & 0b1u);
        curr &= ~(0b1u << 4u);
        curr |= (VC_MMERR & 0b1u) << 4u;
        curr &= ~(0b1u << 5u);
        curr |= (VC_NOCPERR & 0b1u) << 5u;
        curr &= ~(0b1u << 6u);
        curr |= (VC_CHKERR & 0b1u) << 6u;
        curr &= ~(0b1u << 7u);
        curr |= (VC_STATERR & 0b1u) << 7u;
        curr &= ~(0b1u << 8u);
        curr |= (VC_BUSERR & 0b1u) << 8u;
        curr &= ~(0b1u << 9u);
        curr |= (VC_INTERR & 0b1u) << 9u;
        curr &= ~(0b1u << 10u);
        curr |= (VC_HARDERR & 0b1u) << 10u;
        curr &= ~(0b1u << 11u);
        curr |= (VC_SFERR & 0b1u) << 11u;
        curr &= ~(0b1u << 16u);
        curr |= (MON_EN & 0b1u) << 16u;
        curr &= ~(0b1u << 17u);
        curr |= (MON_PEND & 0b1u) << 17u;
        curr &= ~(0b1u << 18u);
        curr |= (MON_STEP & 0b1u) << 18u;
        curr &= ~(0b1u << 19u);
        curr |= (MON_REQ & 0b1u) << 19u;
        curr &= ~(0b1u << 24u);
        curr |= (TRCENA & 0b1u) << 24u;

        DEMCR = curr;
    }

