    /**
     * Get all of FPCCR's bit fields.
     *
     * (read-write) Holds control data for the Floating-point extension
     */
    inline void get_FPCCR(bool &LSPACT, bool &USER, bool &S, bool &THREAD,
                          bool &HFRDY, bool &MMRDY, bool &BFRDY, bool &SFRDY,
                          bool &MONRDY, bool &SPLIMVIOL, bool &UFRDY, bool &TS,
                          bool &CLRONRETS, bool &CLRONRET, bool &LSPENS,
                          bool &LSPEN, bool &ASPEN) volatile
    {
        uint32_t curr = FPCCR;

        LSPACT = curr & 1u;
        USER = curr & (1u << 1u);
        S = curr & (1u << 2u);
        THREAD = curr & (1u << 3u);
        HFRDY = curr & (1u << 4u);
        MMRDY = curr & (1u << 5u);
        BFRDY = curr & (1u << 6u);
        SFRDY = curr & (1u << 7u);
        MONRDY = curr & (1u << 8u);
        SPLIMVIOL = curr & (1u << 9u);
        UFRDY = curr & (1u << 10u);
        TS = curr & (1u << 26u);
        CLRONRETS = curr & (1u << 27u);
        CLRONRET = curr & (1u << 28u);
        LSPENS = curr & (1u << 29u);
        LSPEN = curr & (1u << 30u);
        ASPEN = curr & (1u << 31u);
    }

    /**
     * Set all of FPCCR's bit fields.
     *
     * (read-write) Holds control data for the Floating-point extension
     */
    inline void set_FPCCR(bool LSPACT, bool USER, bool S, bool THREAD,
                          bool HFRDY, bool MMRDY, bool BFRDY, bool SFRDY,
                          bool MONRDY, bool SPLIMVIOL, bool UFRDY, bool TS,
                          bool CLRONRETS, bool CLRONRET, bool LSPENS,
                          bool LSPEN, bool ASPEN) volatile
    {
        uint32_t curr = FPCCR;

        curr &= ~(0b1u);
        curr |= (LSPACT & 0b1u);
        curr &= ~(0b1u << 1u);
        curr |= (USER & 0b1u) << 1u;
        curr &= ~(0b1u << 2u);
        curr |= (S & 0b1u) << 2u;
        curr &= ~(0b1u << 3u);
        curr |= (THREAD & 0b1u) << 3u;
        curr &= ~(0b1u << 4u);
        curr |= (HFRDY & 0b1u) << 4u;
        curr &= ~(0b1u << 5u);
        curr |= (MMRDY & 0b1u) << 5u;
        curr &= ~(0b1u << 6u);
        curr |= (BFRDY & 0b1u) << 6u;
        curr &= ~(0b1u << 7u);
        curr |= (SFRDY & 0b1u) << 7u;
        curr &= ~(0b1u << 8u);
        curr |= (MONRDY & 0b1u) << 8u;
        curr &= ~(0b1u << 9u);
        curr |= (SPLIMVIOL & 0b1u) << 9u;
        curr &= ~(0b1u << 10u);
        curr |= (UFRDY & 0b1u) << 10u;
        curr &= ~(0b1u << 26u);
        curr |= (TS & 0b1u) << 26u;
        curr &= ~(0b1u << 27u);
        curr |= (CLRONRETS & 0b1u) << 27u;
        curr &= ~(0b1u << 28u);
        curr |= (CLRONRET & 0b1u) << 28u;
        curr &= ~(0b1u << 29u);
        curr |= (LSPENS & 0b1u) << 29u;
        curr &= ~(0b1u << 30u);
        curr |= (LSPEN & 0b1u) << 30u;
        curr &= ~(0b1u << 31u);
        curr |= (ASPEN & 0b1u) << 31u;

        FPCCR = curr;
    }

    /**
     * Get FPCAR's ADDRESS field.
     *
     * The location of the unpopulated floating-point register space allocated
     * on an exception stack frame
     */
    inline uint32_t get_FPCAR() volatile
    {
        return (FPCAR >> 3u) & 0b11111111111111111111111111111u;
    }

    /**
     * Set FPCAR's ADDRESS field.
     *
     * The location of the unpopulated floating-point register space allocated
     * on an exception stack frame
     */
    inline void set_FPCAR(uint32_t value) volatile
    {
        uint32_t curr = FPCAR;

        curr &= ~(0b11111111111111111111111111111u << 3u);
        curr |= (value & 0b11111111111111111111111111111u) << 3u;

        FPCAR = curr;
    }

