    /**
     * Get all of FPDSCR's bit fields.
     *
     * (read-write) Holds the default values for the floating-point status
     * control data that the PE assigns to the FPSCR when it creates a new
     * floating-point context
     */
    inline void get_FPDSCR(uint8_t &RMODE, bool &FZ, bool &DN,
                           bool &AHP) volatile
    {
        uint32_t curr = FPDSCR;

        RMODE = (curr >> 22u) & 0b11u;
        FZ = curr & (1u << 24u);
        DN = curr & (1u << 25u);
        AHP = curr & (1u << 26u);
    }

    /**
     * Set all of FPDSCR's bit fields.
     *
     * (read-write) Holds the default values for the floating-point status
     * control data that the PE assigns to the FPSCR when it creates a new
     * floating-point context
     */
    inline void set_FPDSCR(uint8_t RMODE, bool FZ, bool DN, bool AHP) volatile
    {
        uint32_t curr = FPDSCR;

        curr &= ~(0b11u << 22u);
        curr |= (RMODE & 0b11u) << 22u;
        curr &= ~(0b1u << 24u);
        curr |= (FZ & 0b1u) << 24u;
        curr &= ~(0b1u << 25u);
        curr |= (DN & 0b1u) << 25u;
        curr &= ~(0b1u << 26u);
        curr |= (AHP & 0b1u) << 26u;

        FPDSCR = curr;
    }

