    /**
     * Get all of TRCCONFIGR's bit fields.
     *
     * (read-write) The TRCCONFIGR sets the basic tracing options for the trace
     * unit
     */
    inline void get_TRCCONFIGR(bool &BB, bool &CCI, uint8_t &COND, bool &TS,
                               bool &RS) volatile
    {
        uint32_t curr = TRCCONFIGR;

        BB = curr & (1u << 3u);
        CCI = curr & (1u << 4u);
        COND = (curr >> 5u) & 0b111111u;
        TS = curr & (1u << 11u);
        RS = curr & (1u << 12u);
    }

    /**
     * Set all of TRCCONFIGR's bit fields.
     *
     * (read-write) The TRCCONFIGR sets the basic tracing options for the trace
     * unit
     */
    inline void set_TRCCONFIGR(bool BB, bool CCI, uint8_t COND, bool TS,
                               bool RS) volatile
    {
        uint32_t curr = TRCCONFIGR;

        curr &= ~(0b1u << 3u);
        curr |= (BB & 0b1u) << 3u;
        curr &= ~(0b1u << 4u);
        curr |= (CCI & 0b1u) << 4u;
        curr &= ~(0b111111u << 5u);
        curr |= (COND & 0b111111u) << 5u;
        curr &= ~(0b1u << 11u);
        curr |= (TS & 0b1u) << 11u;
        curr &= ~(0b1u << 12u);
        curr |= (RS & 0b1u) << 12u;

        TRCCONFIGR = curr;
    }

