    /**
     * Get all of CTIGATE's bit fields.
     *
     * (read-write) Enable CTI Channel Gate register
     */
    inline void get_CTIGATE(bool &CTIGATEEN0, bool &CTIGATEEN1,
                            bool &CTIGATEEN2, bool &CTIGATEEN3) volatile
    {
        uint32_t curr = CTIGATE;

        CTIGATEEN0 = curr & 1u;
        CTIGATEEN1 = curr & (1u << 1u);
        CTIGATEEN2 = curr & (1u << 2u);
        CTIGATEEN3 = curr & (1u << 3u);
    }

    /**
     * Set all of CTIGATE's bit fields.
     *
     * (read-write) Enable CTI Channel Gate register
     */
    inline void set_CTIGATE(bool CTIGATEEN0, bool CTIGATEEN1, bool CTIGATEEN2,
                            bool CTIGATEEN3) volatile
    {
        uint32_t curr = CTIGATE;

        curr &= ~(0b1u);
        curr |= (CTIGATEEN0 & 0b1u);
        curr &= ~(0b1u << 1u);
        curr |= (CTIGATEEN1 & 0b1u) << 1u;
        curr &= ~(0b1u << 2u);
        curr |= (CTIGATEEN2 & 0b1u) << 2u;
        curr &= ~(0b1u << 3u);
        curr |= (CTIGATEEN3 & 0b1u) << 3u;

        CTIGATE = curr;
    }

